'use client'

import { zodResolver } from '@hookform/resolvers/zod'
import { useHookFormOptimisticAction } from '@next-safe-action/adapter-react-hook-form/hooks'
import { useQueryClient } from '@tanstack/react-query'
import { AnimatePresence, motion } from 'motion/react'
import { USER_MESSAGES } from '@/configs/user-messages'
import { getTransformedDefaultTeamName } from '@/core/modules/teams/utils'
import { updateTeamNameAction } from '@/core/server/actions/team-actions'
import { UpdateTeamNameSchema } from '@/core/server/functions/team/types'
import { useDashboard } from '@/features/dashboard/context'
import {
  defaultErrorToast,
  defaultSuccessToast,
  useToast,
} from '@/lib/hooks/use-toast'
import { exponentialSmoothing } from '@/lib/utils'
import { useTRPC } from '@/trpc/client'
import { Button } from '@/ui/primitives/button'
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/ui/primitives/card'
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormMessage,
} from '@/ui/primitives/form'
import { Input } from '@/ui/primitives/input'

interface NameCardProps {
  className?: string
}

export function NameCard({ className }: NameCardProps) {
  'use no memo'

  const { team } = useDashboard()
  const trpc = useTRPC()
  const queryClient = useQueryClient()

  const { toast } = useToast()

  const {
    form,
    handleSubmitWithAction,
    action: { isExecuting, optimisticState },
  } = useHookFormOptimisticAction(
    updateTeamNameAction,
    zodResolver(UpdateTeamNameSchema),
    {
      formProps: {
        defaultValues: {
          teamSlug: team.slug,
          name: team.name,
        },
      },
      actionProps: {
        currentState: {
          team,
        },
        updateFn: (state, input) => {
          if (!state.team) return state

          return {
            team: {
              ...state.team,
              name: input.name,
            },
          }
        },
        onSuccess: async () => {
          await queryClient.invalidateQueries({
            queryKey: trpc.teams.list.queryKey(),
          })
          toast(defaultSuccessToast(USER_MESSAGES.teamNameUpdated.message))
        },
        onError: ({ error }) => {
          if (!error.serverError) return

          toast(
            defaultErrorToast(
              error.serverError || USER_MESSAGES.failedUpdateTeamName.message
            )
          )
        },
      },
    }
  )

  const { watch } = form
  const displayedNameHint = getTransformedDefaultTeamName(
    optimisticState?.team ?? team
  )

  return (
    <Card className={className}>
      <CardHeader>
        <CardTitle>Name</CardTitle>
        <CardDescription>
          Change your team name to display on your invoices and receipts.
        </CardDescription>
      </CardHeader>
      <CardContent className="py-0 max-h-full">
        <Form {...form}>
          <form
            onSubmit={handleSubmitWithAction}
            className="flex max-w-sm gap-2 mt-auto"
          >
            <FormField
              control={form.control}
              name="name"
              render={({ field }) => (
                <FormItem className="flex-1 gap-1 p-0">
                  <FormControl>
                    <Input placeholder="Acme, Inc." {...field} />
                  </FormControl>
                  <AnimatePresence initial={false}>
                    {displayedNameHint && (
                      <motion.span
                        className="text-fg-tertiary ml-0.5 text-xs"
                        animate={{
                          opacity: 1,
                          filter: 'blur(0px)',
                          height: 'auto',
                        }}
                        exit={{ opacity: 0, filter: 'blur(4px)', height: 0 }}
                        transition={{
                          duration: 0.4,
                          ease: exponentialSmoothing(3),
                        }}
                      >
                        Seen as -{' '}
                        <span className="text-accent-info-highlight">
                          {displayedNameHint}
                        </span>
                      </motion.span>
                    )}
                  </AnimatePresence>
                  <FormMessage className="mt-1" />
                </FormItem>
              )}
            />
            <Button
              type="submit"
              variant="outline"
              loading={isExecuting}
              disabled={watch('name') === optimisticState?.team?.name}
            >
              Save
            </Button>
          </form>
        </Form>
      </CardContent>
    </Card>
  )
}
